ox.APIs(''produceTask.advanceCharge'').setValue(false);\n                // 清空''放料条件''且只读\n                var _feedConditionComponent = ReactAPI.getComponentAPI().Input.APIs(''produceTask.feedCondition'');\n                _feedConditionComponent.setReadonly(true);\n                _feedConditionComponent.setValue('''');\n                // 清空''质量标准''\n                ReactAPI.getComponentAPI().Reference.APIs(''produceTask.qualityStdId.name'').removeValue();\n            }\n        });\n    }\n    //判断产品编码是否为危化品\n    var data = ReactAPI.getComponentAPI(\"Reference\").APIs(\"produceTask.productId.code\").getValue();\n    var materialCode = void 0;\n    if (data[0] != null && data[0].id != null) {\n        //有数据\n        materialCode = data[0].id;\n        ReactAPI.request({\n            type: \"get\",\n            ///RM/formulaBOM/formulaBomMain/GetMaterialAttribute\n            url: \"/msService/WOM/produceTask/produceTask/GetMaterialAttribute?materialCode=\" + materialCode,\n            contentType: \"application/json;charset=UTF-8\"\n        }, function (res) {\n            if (res.success) {\n                if (res.data.materialAttr == true) {\n                    //如果是危化品则为红色\n                    document.getElementsByClassName(\"ant-input ant-select-search__field\")[0].style.color = \"#B30303\";\n                } else {\n                    document.getElementsByClassName(\"ant-input ant-select-search__field\")[0].style.color = \"#505050\";\n                }\n                console.log(res.data.materialAttr);\n                console.log(res.data);\n            } else {\n                console.log(res.msg);\n            }\n        });\n    }\n}","callbackbody":"function productRefCallback(products) {\ndebugger;\n    if (products.length) {\n        // 选中产品后，如有该产品的默认配方，直接带出\n        let product = products[0];\n        // 根据产品id获取该产品默认配方\n        ReactAPI.request({\n            type: \"get\",\n            url: ''/msService/RM/formula/formula/default/product/