e":"WOM_1.0.0_produceTask_ProduceTask_actualPlanNum","saveTemplate":false,"isCustom":false,"openEmptyDoc":true,"multable":false,"columnName":"ACTUAL_PLAN_NUM"},"firstTd":0},{"colspan":1,"firstTd":1,"regionType":"EDIT","rowspan":1,"cellCode":"cell_1577348327986_8162","name":"配方编码","element":{"showTypeHasChanged":true,"couple":true,"acceptRevisions":false,"code":"WOM_1.0.0_produceTask_makeTaskEdit_EDIT_LABEL_WOM_1.0.0_produceTask_ProduceTask_formulaId_RM_1.0.0_formula_Formula_formualCode","iscontrol":false,"nullable":false,"displayName":"RM.formula.Formula.formualCode","isOfficeHandSign":false,"multallowview":false,"isRevision":false,"showFormatHasChanged":true,"hideRevision":false,"getRevisions":false,"allowview":false,"propertyCode":"WOM_1.0.0_produceTask_ProduceTask_formulaId||RM_1.0.0_formula_Formula_formualCode","elalign":"right","readonly":false,"showRevision":false,"convertPdfOnLine":true,"complex":false,"namekey":"RM.formula.Formula.formualCode","isreadonly":false,"isgroup":false,"showType":"LABEL","officePrint":false,"isCreateNew":false,"key":"produceTask.formulaId.formualCode","downloadDoc":true,"entityCode":"WOM_1.0.0_produceTask","moduleCode":"WOM_1.0.0","showFormat":"TEXT","officeNotNull":false,"autoresize":false,"mneenable":false,"fullPropertyCode":"WOM_1.0.0_produceTask_ProduceTask_formulaId||RM_1.0.0_formula_Formula_formualCode","isOfficeSign":false,"columnType":"BAPCODE","isTitle":true,"isrefselect":false,"saveTemplate":false,"isCustom":false,"name":"配方编码","openEmptyDoc":true,"isNoCopy":false,"multable":false,"columnName":"FORMUAL_CODE"}},{"callbackbody_es5":"function formulaRefCallback(formulas) {\n    if (!formulas.length) {\n        return;\n    }\n    var formula = formulas[0];\n    //通过配方id查询出配方对象信息\n    $.ajax({\n        type: \"get\",\n        async: false,\n        url: \"/msService/RM/formula/formula/findFormulaById\",\n        data: {\n            id: formula.id\n        },\n        success: function success(res) {\n            if (res.code == 200 && res.data.successFlag) {\n                formula = res.data.data;\n            }\n        },\n        error: function error(res) {\n            ReactAPI.showMessage(\"f\", res.message);\n            return;\n        }\n    });\n    // 产品输入框\n    ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.productId.code'').setValue(formula.productId);\n    // 设置是否批控\n    ReactAPI.getComponentAPI(''Checkbox'').APIs(''produceTask.batchContral'').setValue(formula.batchContral);\n    // 适用产线清空\n    ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.lineId.name'').removeValue();\n    // 工序活动、用料汇总、检验清单页签均隐藏\n    $(\"[role=''tab'']:gt(0)\").hide();\n    var dataGrid = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskEditdg1575441036618\");\n    if (formula.setProcess.id == ''RM_formulaType/simpleFormula'') {\n        dataGrid.setColumnsHideOrShow(\"taskProcessId.name\", false);\n        dataGrid.setColumnsHideOrShow(\"name\", false);\n        dataGrid.setColumnsHideOrShow(\"activeType\", false);\n    } else {\n        dataGrid.setColumnsHideOrShow(\"taskProcessId.name\", true);\n        dataGrid.setColumnsHideOrShow(\"name\", true);\n        dataGrid.setColumnsHideOrShow(\"activeType\", true);\n    }\n    //检验时机\n    var inspectTimer = ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.inspectTimer\");\n    inspectTimer.setReadonly(true);\n    if (formula.inspectTimer != null) {\n        inspectTimer.setValue(formula.inspectTimer.id);\n        var inspectValue = inspectTimer.getValue().value;\n        if (inspectValue != '''' && inspectValue != \"RM_inspectTimer/active\") {\n            ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setRequired(true);\n            ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(true);\n            ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setReadonly(false);\n        }\n    } else {\n        ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setRequired(false);\n        ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(false);\n        ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setReadonly(true);\n    }\n    //\n    var qualityStdId = ReactAPI.getComponentAPI().Reference.APIs(''produceTask.qualityStdId.name'');\n    if (formula.qualityStdId && formula.qualityStdId.id) {\n        qualityStdId.setValue(formula.qualityStdId);\n    } else {\n        qualityStdId.removeValue();\n    }\n    //报工模式 \n    if (formula.reportType != undefined) {\n        ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.reportType\").setValue(formula.reportType.id);\n    }\n    // ''允许提前放料''及''放料条件''\n    var advanceCharge = ReactAPI.getComponentAPI().Checkbox.APIs(''produceTask.advanceCharge'');\n    var feedCondition = ReactAPI.getComponentAPI().Input.APIs(''produceTask.feedCondition'');\n    advanceCharge.setValue(formula.advanceCharge ? true : false);\n    feedCondition.setReadonly(formula.advanceCharge ? false : true);\n    feedCondition.setValue(formula.feedCondition);\n    // 改变配方编码的点击样式\n    $(''#label_produceTask_formulaId_formualCode'').html(window._supcon_target_html);\n}","callbackbody":"function formulaRefCallback(formulas) {\n    if (!formulas.length) {\n        return;\n    }\n    let formula = formulas[0];\n    //通过配方id查询出配方对象信息\n    $.ajax({\n        type: \"get\",\n        async: false,\n        url: \"/msService/RM/formula/formula/findFormulaById\",\n        data: {\n            id: formula.id\n        },\n        success: function (res) {\n            if(res.code == 200 && res.data.successFlag) {\n                formula = res.data.data;\n            }\n            \n        },\n        error: function (res) {\n            ReactAPI.showMessage(\"f\", res.message);\n            return;\n        }\n    });\n    // 产品输入框\n    ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.productId.code'').setValue(formula.productId);\n    // 设置是否批控\n    ReactAPI.getComponentAPI(''Checkbox'').APIs(''produceTask.batchContral'').setValue(formula.batchContral);\n    // 适用产线清空\n    ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.lineId.name'').removeValue();\n    // 工序活动、用料汇总、检验清单页签均隐藏\n    $(\"[role=''tab'']:gt(0)\").hide();\n    let dataGrid = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskEditdg1575441036618\");\n    if (formula.setProcess.id == ''RM_formulaType/simpleFormula'') {\n        dataGrid.setColumnsHideOrShow(\"taskProcessId.name\", false);\n        dataGrid.setColumnsHideOrShow(\"name\", false);\n        dataGrid.setColumnsHideOrShow(\"activeType\", false);\n    } else {\n        dataGrid.setColumnsHideOrShow(\"taskProcessId.name\", true);\n        dataGrid.setColumnsHideOrShow(\"name\", true);\n        dataGrid.setColumnsHideOrShow(\"activeType\", true);\n    }\n    //检验时机\n    let inspectTimer=ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.inspectTimer\");\n    inspectTimer.setReadonly(true);\n    if (formula.inspectTimer != null ) {\n        inspectTimer.setValue(formula.inspectTimer.id);\n        let inspectValue=inspectTimer.getValue().value;\n        if(inspectValue!='''' && inspectValue!=\"RM_inspectTimer/active\"){\n            ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setRequired(true);\n            ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(true); \n            ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setReadonly(false);\n        }\n    } else {\n        ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setRequired(false);\n        ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(false); \n        ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'').setReadonly(true)\n    }\n    //\n    let qualityStdId = ReactAPI.getComponentAPI().Reference.APIs(''produceTask.qualityStdId.name'');\n    if (formula.qualityStdId && formula.qualityStdId.id) {\n        qualityStdId.setValue(formula.qualityStdId);\n    } else {\n        qualityStdId.removeValue();\n    }\n    //报工模式 \n    if(formula.reportType!=undefined){\n        ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.reportType\").setValue(formula.reportType.id);\n    }\n    // ''允许提前放料''及''放料条件''\n    let advanceCharge = ReactAPI.getComponentAPI().Checkbox.APIs(''produceTask.advanceCharge'');\n    let feedCondition = ReactAPI.getComponentAPI().Input.APIs(''produceTask.feedCondition'');\n    advanceCharge.setValue(formula.advanceCharge ? true : false);\n    feedCondition.setReadonly(formula.advanceCharge ? false : true);\n    feedCondition.setValue(formula.feedCondition);\n    // 改变配方编码的点击样式\n    $(''#label_produceTask_formulaId_formualCode'').html(window._supcon_target_html);\n}","funcbody":"function onFormulaRefClear(deleteObj) {\n    // 适用产线清空\n   ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.lineId.name'').removeValue();\n    ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.reportType\").removeValue();\n    ReactAPI.getComponentAPI(\"Reference\").APIs(\"produceTask.workAreaId.name\").removeValue();\n\n    // 设置是否批控\n    ReactAPI.getComponentAPI(''Checkbox'').APIs(''produceTask.batchContral'').setValue(false);\n    // 工序活动、用料汇总、检验清单页签均隐藏\n    $(\"[role=''tab'']:gt(0)\").hide();\n\n    // ''完工后检验''置为false\n    //ReactAPI.getComponentAPI().Checkbox.APIs(''produceTask.insAfterManu'').setValue(false);\n    let inspectTimer=ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.inspectTimer\");\n    let qualityStd = ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'');\n\n    inspectTimer.setReadonly(true);\n    inspectTimer.removeValue();\n    // 清空''质量标准''且只读\n    qualityStd.removeValue();\n    qualityStd.setReadonly(true);\n    qualityStd.setRequired(false);\n    ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(false);\n    // ''允许提前放料''置为false\n    ReactAPI.getComponentAPI().Checkbox.APIs(''produceTask.advanceCharge'').setValue(false);\n    // 清空''放料条件''且只读\n    let feedConditionComponent = ReactAPI.getComponentAPI().Input.APIs(''produceTask.feedCondition'');\n    feedConditionComponent.setReadonly(true);\n    feedConditionComponent.setValue('''');\n\t\n\t// 改变配方编码的点击样式\n\t$(''#label_produceTask_formulaId_formualCode'').html(window._supcon_origin_html);\n}","funcname":"onAfterClear=''onFormulaRefClear(deleteObj)''","cellCode":"cell_1577348327987_6230","colspan":1,"sourcepropertyname":"produceTask.formulaId","regionType":"EDIT","topAssName":"id","rowspan":1,"funcbody_es5":"function onFormulaRefClear(deleteObj) {\n  // 适用产线清空\n  ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.lineId.name'').removeValue();\n  ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.reportType\").removeValue();\n  ReactAPI.getComponentAPI(\"Reference\").APIs(\"produceTask.workAreaId.name\").removeValue();\n\n  // 设置是否批控\n  ReactAPI.getComponentAPI(''Checkbox'').APIs(''produceTask.batchContral'').setValue(false);\n  // 工序活动、用料汇总、检验清单页签均隐藏\n  $(\"[role=''tab'']:gt(0)\").hide();\n\n  // ''完工后检验''置为false\n  //ReactAPI.getComponentAPI().Checkbox.APIs(''produceTask.insAfterManu'').setValue(false);\n  var inspectTimer = ReactAPI.getComponentAPI(\"SystemCode\").APIs(\"produceTask.inspectTimer\");\n  var qualityStd = ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.qualityStdId.name'');\n\n  inspectTimer.setReadonly(true);\n  inspectTimer.removeValue();\n  // 清空''质量标准''且只读\n  qualityStd.removeValue();\n  qualityStd.setReadonly(true);\n  qualityStd.setRequired(false);\n  ReactAPI.getComponentAPI().Label.APIs(''produceTask.qualityStdId.name'').setNullableStyle(false);\n  // ''允许提前放料''