{\n        // 选中产品后，如有该产品的默认配方，直接带出\n        let product = products[0];\n        // 根据产品id获取该产品默认配方\n        ReactAPI.request(\n            {\n                type: \"get\",\n                url: ''/msService/RM/formula/formula/default/product/'' + product.id,\n            },\n            res => {\n                // 配方输入框\n                let formualComponent = ReactAPI.getComponentAPI(''Reference'').APIs(''produceTask.formulaId.formualCode'');\n                if (res.success) {\n                    // 有默认配方，设置配方输入框的值\n                    formualComponent.setValue(res.data);\n                } else {\n                    // 没有默认配方，则清空配方输入框\n                    formualComponent.removeValue();\n                }\n\n            }\n        );\n    }\n    //判断产品编码是否为危化品\n    let data = ReactAPI.getComponentAPI(\"Reference\").APIs(\"produceTask.productId.code\").getValue();\n    let materialCode;\n    if (data[0] != null && data[0].id != null) {//有数据\n        materialCode = data[0].id;\n        ReactAPI.request({\n            type: \"get\",\n            ///RM/formulaBOM/formulaBomMain/GetMaterialAttribute\n            url: \"/msService/RM/formulaBOM/formulaBomMain/GetMaterialAttribute?materialCode=\" + materialCode,\n            contentType: \"application/json;charset=UTF-8\",\n        }, function (res) {\n            if (res.success) {\n                if (res.data.materialAttr == true) {//如果是危化品则为红色\n                    document.getElementsByClassName(\"supplant-ellipsis-wrap\")[0].style.color = \"#B30303\";\n                }\n                else {\n                    document.getElementsByClassName(\"supplant-ellipsis-wrap\")[0].style.color = \"#505050\";\n                }\n            }\n        }\n        );\n    }\n}","funcbody":"","funcname":"","cellCode":"cell_1577690312348_9013","colspan":1,"sourcepropertyname":"produceTask.productId","regionType":"EDIT","topAssName":"id","rowspan":1,"funcbody_es5":"","callbackname":"productRefCallback(products)","element":