ibute\n                url: \"/msService/WOM/produceTask/produceTask/GetMaterialAttribute?materialCode=\"+materialCode,\n                contentType: \"application/json;charset=UTF-8\",\n            }, function (res) {\n                if(res.success){\n                    if(res.data.materialAttr==true){//如果是危化品则为红色\n                        document.getElementsByClassName(\"supplant-ellipsis-wrap\")[2].style.color=\"#B30303\";\t\n                    }\n                    else{\n                        document.getElementsByClassName(\"supplant-ellipsis-wrap\")[2].style.color=\"#505050\";\n                    }\n                  console.log(res.data.materialAttr);\t\n                  console.log(res.data);\n                }else{\t\n                    console.log(res.msg);\n                }\n            }\n            );\n        }\n}","funcbody":"","funcname":"","cellCode":"cell_1577777029193_2138","colspan":1,"sourcepropertyname":"produceTask.productId","regionType":"EDIT","topAssName":"id","rowspan":1,"funcbody_es5":"","callbackname":"productRefCallback(products)","element":{"showTypeHasChanged":false,"couple":true,"iscontrol":false,"nullable":false,"isOfficeHandSign":false,"isRevision":false,"showFormatHasChanged":false,"defaultValueHasChanged":false,"referenceview":{"title":"BaseSet.viewtitle.randon1569570764419","code":"BaseSet_1.0.0_material_materialRefLayout","name":"materialRefLayout","openType":"frame","url":"/msService/BaseSet/material/material/materialRefLayout","iscrosscompany":"false","mneType":"other"},"propertyCode":"WOM_1.0.0_produceTask_ProduceTask_productId||BaseSet_1.0.0_material_Material_code","elalign":"left","readonly":true,"convertPdfOnLine":true,"complex":false,"isgroup":false,"showType":"SELECTCOMP","isCreateNew":false,"officeNotNull":false,"mneenable":true,"isOfficeSign":false,"columnType":"TEXT","isTitle":true,"isrefselect":false,"modelcode":"BaseSet_1.0.0_material_Material","name":"produceTask.productId.code","isNoCopy":false,"preci